function s(e,t){switch(t){case'min':return e/60;case'h':return e;case'tag':return e*24;case'monat':return e*24*30;case'jahr':return e*24*365;default:return e}}function f(e){return e.toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:4})+' €'}function v(e,t){const n=parseFloat(e);if(e==='')return{valid:!1,message:t+' darf nicht leer sein'};if(isNaN(n))return{valid:!1,message:t+' muss eine Zahl sein'};if(n<0)return{valid:!1,message:t+' darf nicht negativ sein'};if(!Number.isFinite(n))return{valid:!1,message:t+' ist zu groß'};return{valid:!0}}function c(){const e=document.getElementById('leistung'),t=document.getElementById('leistungError'),r=document.getElementById('zeit'),a=document.getElementById('zeitError'),i=document.getElementById('preis'),l=document.getElementById('preisError'),d=document.getElementById('grundpreis'),u=document.getElementById('grundpreisError');let h=!0;const g=v(e.value,'Leistung');if(!g.valid){t.textContent=g.message;t.style.display='block';e.classList.add('input-error');h=!1}else{t.style.display='none';e.classList.remove('input-error')}const m=v(r.value,'Nutzungsdauer');if(!m.valid){a.textContent=m.message;a.style.display='block';r.classList.add('input-error');h=!1}else{a.style.display='none';r.classList.remove('input-error')}const y=v(i.value,'Arbeitspreis');if(!y.valid){l.textContent=y.message;l.style.display='block';i.classList.add('input-error');h=!1}else{l.style.display='none';i.classList.remove('input-error')}const p=v(d.value,'Grundpreis');if(!p.valid){u.textContent=p.message;u.style.display='block';d.classList.add('input-error');h=!1}else{u.style.display='none';d.classList.remove('input-error')}return h}function b(){if(!c())return;const e=parseFloat(document.getElementById('leistung').value)||0,t=document.getElementById('leistungEinheit').value,r=parseFloat(document.getElementById('zeit').value)||0,n=document.getElementById('zeitEinheit').value,a=parseFloat(document.getElementById('preis').value)||0,i=parseFloat(document.getElementById('grundpreis').value)||0,o=document.getElementById('grundpreisEinheit').value,l=t==='kW'?e:e/1e3,u=s(r,n),d=l*u,p=a/100,h=d*p,m=p*l,y=o==='jahr'?i/365:i/30,g=y*(u/24),v=d*h;document.getElementById('outKwh').textContent=d.toLocaleString('de-DE',{maximumFractionDigits:4})+' kWh';document.getElementById('outKosten').textContent=f(h);document.getElementById('outProStunde').textContent=f(m);document.getElementById('outProTag').textContent=f(y);document.getElementById('outGrundpreisAnteil').textContent=f(g);document.getElementById('outGesamt').textContent=f(v)}document.querySelectorAll('input,select').forEach(e=>{e.addEventListener('input',()=>{c();b()})});b();